example.code:
// BAD — timeout may drop the transaction mid-flight
tokio::select! {
    result = db.transaction(|tx| async { tx.insert(...).await }) => result?,
    _ = tokio::time::sleep(Duration::from_secs(5)) => Err(AppError::Timeout),
}

// GOOD — timeout wraps the entire operation; cancellation is safe at the boundary
tokio::time::timeout(
    Duration::from_secs(5),
    db.transaction(|tx| async { tx.insert(...).await })
).await
  .map_err(|_| AppError::Timeout)??
